create extension if not exists "pgcrypto";
create table if not exists profiles (id uuid primary key default gen_random_uuid(), name text not null, height numeric(4,2) not null, birth_date date not null, goal text not null, created_at timestamptz not null default now());
create table if not exists body_metrics (id uuid primary key default gen_random_uuid(), profile_id uuid not null references profiles(id) on delete cascade, date date not null default current_date, weight numeric(5,2) not null, waist numeric(5,2) not null, neck numeric(5,2) not null, chest numeric(5,2) not null, arm numeric(5,2) not null, unique(profile_id,date));
create table if not exists workouts (id uuid primary key default gen_random_uuid(), profile_id uuid not null references profiles(id) on delete cascade, date date not null default current_date, duration integer not null check (duration > 0));
create table if not exists workout_exercises (id uuid primary key default gen_random_uuid(), workout_id uuid not null references workouts(id) on delete cascade, exercise_name text not null, sets integer not null check (sets > 0), reps integer not null check (reps > 0), rpe numeric(3,1) not null check (rpe between 1 and 10));
create table if not exists habits (id uuid primary key default gen_random_uuid(), profile_id uuid not null references profiles(id) on delete cascade, date date not null default current_date, water numeric(4,2) not null default 0, sleep numeric(4,2) not null default 0, steps integer not null default 0, protein numeric(5,2) not null default 0, unique(profile_id,date));
alter table profiles enable row level security; alter table body_metrics enable row level security; alter table workouts enable row level security; alter table workout_exercises enable row level security; alter table habits enable row level security;
